(1, 'How to upgrade to PHP 8.3 in Laragon', 'how-to-upgrade-to-php-8-3-in-laragon', '{\"en\":\"how-to-upgrade-to-php-8-3-in-laragon\",\"vi\":\"huong-dan-nang-cap-len-php-8-3-trong-laragon\"}', 'active', 'how to upgrade to php 8 3 in laragon', '<p class=\"text-[16px] leading-[24px] font-normal text-home-body mb-12 font-plus\">PHP 8.4 brings massive performance improvements and new features like property hooks. Laragon makes it incredibly easy to switch PHP versions without touching system environment variables. Here is how to do it in 3 minutes.</p>\r\n<h3 class=\"text-[24px] sm:text-[24px] leading-[30px] sm:leading-[36px] font-semibold text-home-heading mb-3 font-plus\">Step 1: Download PHP 8.4</h3>\r\n<p class=\"text-[16px] leading-[24px] font-normal text-home-body mb-6 font-plus\">First, you need to download the PHP binary for Windows. Since Laragon uses Apache, we usually need the Thread Safe (TS) version, but Laragon handles Non-Thread Safe (NTS) well too with FastCGI. For best compatibility, let\'s grab the VS17 x64 Thread Safe zip.</p>\r\n<div class=\"relative w-full rounded-home-md overflow-hidden mt-8\"><img class=\"w-full h-full object-cover brightness-110 contrast-115\" style=\"max-width: 100%; height: auto;\" src=\"https://laragon.net/content/themes/cmsfullform/Frontend/assets/images/img-erol-1.png\" alt=\"\"></div>\r\n<h3 class=\"text-[24px] sm:text-[24px] leading-[30px] sm:leading-[36px] font-semibold text-home-heading mb-3 font-plus mt-12\">Step 2: Extract to Laragon</h3>\r\n<p class=\"text-[16px] leading-[24px] font-normal text-home-body mb-6 font-plus\">Locate your Laragon installation folder (usually C:\\laragon). Navigate to the PHP bin folder and create a new folder for the version.</p>\r\n<div class=\"relative w-full rounded-home-md overflow-hidden mt-8\"><img class=\"w-full h-full object-cover brightness-110 contrast-115\" style=\"max-width: 100%; height: auto;\" src=\"https://laragon.net/content/themes/cmsfullform/Frontend/assets/images/img-erol-1.png\" alt=\"\"></div>\r\n<div class=\"relative w-full rounded-home-md overflow-hidden mt-8\r\n                \"><img class=\"w-full h-full object-cover brightness-110 contrast-115\" style=\"max-width: 100%; height: auto;\" src=\"https://laragon.net/content/themes/cmsfullform/Frontend/assets/images/img-erol-1.png\" alt=\"\"></div>\r\n<h3 class=\"text-[24px] sm:text-[24px] leading-[30px] sm:leading-[36px] font-semibold text-home-heading mb-3 font-plus mt-12\">Step 3: Select Version</h3>\r\n<p class=\"text-[16px] leading-[24px] font-normal text-home-body mb-12 font-plus\">Open Laragon interface. Go to Menu &gt; PHP &gt; Version and select the new 8.4 version. Laragon will automatically restart Apache to apply changes.</p>', 'asdasd', 'awwwwww', '{\"id\":129,\"name\":\"tutorials1-1.jpg\",\"path\":\"2026/03/31/tutorials1-1.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"400\",\"height\":\"200\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"320\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"500\"}],\"webp\":1}', '2026-03-10 16:03:51', '2026-04-15 19:44:38', '{\"id\":79,\"name\":\"albertflores.jpg\",\"path\":\"2026/03/10/albertflores.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', 'Wade Warren', 'Learn step by step how to configure, customize, and optimize your development environment for better performance, smoother workflows, and a more efficient coding experience.', 'Note: If you don\'t see the new version, try Stop → Start again.', '[{\"tag_name\":\"#PHP\"},{\"tag_name\":\"#Config\"},{\"tag_name\":\"#Laragon\"}]'),
(3, 'Setting up Laravel 11 with Laragon', 'setting-up-laravel-11-with-laragon', '', 'active', 'setting up laravel 11 with laragon', '', '', '', '{\"id\":130,\"name\":\"tutorials1.jpg\",\"path\":\"2026/03/31/tutorials1.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"400\",\"height\":\"200\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"320\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"500\"}],\"webp\":1}', '2026-03-10 16:08:17', '2026-03-31 14:37:55', '{\"id\":75,\"name\":\"user3.jpg\",\"path\":\"2026/03/10/user3.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', 'Devon Lane', 'Learn step-by-step how to configure and optimize your environment for the best performance...', '', '[]'),
