INSERT INTO `fast_customer_en` (`id`, `title`, `slug`, `lang_slug`, `status`, `search_string`, `description`, `content`, `seo_title`, `seo_desc`, `avatar`, `created_at`, `updated_at`, `rating_total`, `rating_count`, `rating_avg`) VALUES
(1, 'Daniel Bachmann', 'daniel-bachmann', '', 'active', 'daniel bachmann', 'Tweet about webmarketing', '<p>Laragon is really an awesome local server. You must try it for your local dev. A big thank you @leovn</p>\r\n', '', '', '{\"id\":73,\"name\":\"user1.jpg\",\"path\":\"2026/03/10/user1.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', '2026-03-10 13:19:09', '2026-03-10 15:29:42', 0, 0, 0.00),
(2, 'Bastien', 'bastien', '', 'active', 'bastien', 'Tweet about webmarketing', '<p>I will soon return to WordPress to code and set up a blog. After testing Laragon, I really like it. It is easy to use, highly flexible, and by far the fastest local development environment for Windows that I have ever tested.</p>', '', '', '{\"id\":75,\"name\":\"user3.jpg\",\"path\":\"2026/03/10/user3.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', '2026-03-10 13:27:48', '2026-03-10 15:26:43', 0, 0, 0.00),
(3, 'Phrank', 'phrank', '', 'active', 'phrank', '', '<p>Hey @leovn , thank you very much for Laragon, I just convinced some hard core Linux fans to take a look and they were extremely impressed! Keep up the great job you\'re doing.</p>', '', '', '{\"id\":74,\"name\":\"user2.jpg\",\"path\":\"2026/03/10/user2.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', '2026-03-10 13:33:17', '2026-03-10 15:28:40', 0, 0, 0.00),
(4, 'Nguyen Van A', 'nguen-van-a', '', 'active', 'nguen van a', 'HIHIHIH', '<p>HIHIHIH</p>', '', '', '{\"id\":76,\"name\":\"albertflores.jpg\",\"path\":\"2026/03/10/albertflores.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', '2026-03-10 15:42:20', '2026-03-10 15:51:19', 0, 0, 0.00);

