INSERT INTO `fast_customer_vi` (`id`, `title`, `slug`, `lang_slug`, `status`, `search_string`, `description`, `content`, `seo_title`, `seo_desc`, `avatar`, `created_at`, `updated_at`, `rating_total`, `rating_count`, `rating_avg`) VALUES
(1, 'Daniel Bachmann', 'daniel-bachmann', '', 'active', 'daniel bachmann', 'Tweet about webmarketing', '<p>Laragon thực sự là một máy chủ cục bộ tuyệt vời. Bạn nhất định phải thử nó cho việc phát triển cục bộ của mình. Cảm ơn rất nhiều @leovn</p>\r\n', '', '', '{\"id\":73,\"name\":\"user1.jpg\",\"path\":\"2026/03/10/user1.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', '2026-03-10 13:19:09', '2026-03-10 15:29:42', 0, 0, 0.00),
(2, 'Bastien', 'bastien', '', 'active', 'bastien', 'Tweet about webmarketing', '<p>Tôi sẽ sớm quay lại WordPress để lập trình và thiết lập blog. Sau khi thử nghiệm Laragon, tôi thực sự rất thích nó. Nó dễ sử dụng, rất linh hoạt và cho đến nay là môi trường phát triển cục bộ nhanh nhất dành cho Windows mà tôi từng thử nghiệm.</p>', '', '', '{\"id\":75,\"name\":\"user3.jpg\",\"path\":\"2026/03/10/user3.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', '2026-03-10 13:27:48', '2026-03-10 15:26:43', 0, 0, 0.00),
(3, 'Phrank&amp;amp;amp;#039;o', 'phrank-o', '', 'active', 'phrank o', '', '<p>Chào @leovn, cảm ơn bạn rất nhiều về Laragon, tôi vừa thuyết phục được một số người hâm mộ Linux lâu năm dùng thử và họ vô cùng ấn tượng! Hãy tiếp tục công việc tuyệt vời này nhé.</p>', '', '', '{\"id\":74,\"name\":\"user2.jpg\",\"path\":\"2026/03/10/user2.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', '2026-03-10 13:33:17', '2026-03-10 15:28:40', 0, 0, 0.00),
(4, 'Nguyễn Văn A', 'nguyen-van-a', '', 'active', 'nguyen van a', 'Xin Chào nhé', '<p>Xin Ch&agrave;o c&aacute;c bạn</p>', '', '', '{\"id\":76,\"name\":\"albertflores.jpg\",\"path\":\"2026/03/10/albertflores.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', '2026-03-10 15:42:20', '2026-03-10 15:51:19', 0, 0, 0.00);

