  `webp` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Has WebP variant (0=no, 1=yes)'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

