--
-- Table structure for table `fast_postrating_votes`
--

CREATE TABLE `fast_postrating_votes` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `posttype` varchar(191) NOT NULL,
  `post_id` int(10) UNSIGNED NOT NULL,
  `lang` varchar(16) NOT NULL,
  `voter_type` tinyint(3) UNSIGNED NOT NULL COMMENT '1=user,2=guest',
  `voter_key` varchar(64) NOT NULL,
  `rating_value` tinyint(3) UNSIGNED NOT NULL,
  `ip_hash` char(64) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Table structure for table `fast_posttype`
--

CREATE TABLE `fast_posttype` (
  `id` int(10) UNSIGNED NOT NULL,
  `current_id` int(10) UNSIGNED DEFAULT 0,
  `name` varchar(100) NOT NULL,
  `slug` varchar(100) NOT NULL,
  `fields` longtext DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `languages` longtext DEFAULT NULL,
  `terms` longtext DEFAULT NULL,
  `status` enum('active','inactive') NOT NULL DEFAULT 'active',
  `menu` varchar(100) NOT NULL,
  `is_locked` tinyint(4) NOT NULL DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

