CREATE TABLE `fast_reviews_en` (
  `id` int(10) UNSIGNED NOT NULL,
  `title` varchar(190) DEFAULT NULL,
  `slug` varchar(190) DEFAULT NULL,
  `lang_slug` text DEFAULT NULL,
  `status` varchar(30) DEFAULT 'active',
  `search_string` varchar(190) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `label` longtext DEFAULT NULL,
  `seo_title` varchar(190) DEFAULT NULL,
  `seo_desc` varchar(190) DEFAULT NULL,
  `feature` text DEFAULT NULL,
  `rating_avg` double DEFAULT 0,
  `performance` int(11) DEFAULT NULL,
  `link` varchar(255) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `pro` longtext DEFAULT NULL,
  `cons` longtext DEFAULT NULL,
  `performance_user` int(11) DEFAULT NULL,
  `rating_total` int(11) DEFAULT 0,
  `rating_count` int(11) DEFAULT 0,
  `content` longtext DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

