INSERT INTO `fast_reviews_vi` (`id`, `title`, `slug`, `lang_slug`, `status`, `search_string`, `description`, `label`, `seo_title`, `seo_desc`, `feature`, `rating_avg`, `performance`, `link`, `created_at`, `updated_at`, `pro`, `cons`, `performance_user`, `rating_total`, `rating_count`, `content`) VALUES
(3, 'WordPress', 'wordpress', '{\"en\":\"wordpress\",\"vi\":\"wordpress\"}', 'active', 'wordpress', 'Hệ quản trị nội dung (CMS) phổ biến nhất thế giới. Sở hữu hệ sinh thái plugin và giao diện (theme) vô cùng phong phú', 'Rising Star', '', '', '{\"id\":86,\"name\":\"ef1947af9f93673da412ef37769eab4a.jpg\",\"path\":\"2026/03/21/ef1947af9f93673da412ef37769eab4a.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', 5, 70, '', '2026-03-21 17:09:16', '2026-04-15 21:11:34', '[{\"pro_detail\":\"Dễ sử dụng\"},{\"pro_detail\":\"Cộng đồng lớn\"},{\"pro_detail\":\"Hàng nghìn plugin\"}]', '[{\"cons_detail\":\"Có thể chậm\"},{\"cons_detail\":\"Lỗ hổng bảo mật\"},{\"cons_detail\":\"Xung đột plugin\"}]', 43, NULL, NULL, '<h2 class=\"detail-sapo\" data-role=\"sapo\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m đề nghị cơ quan lập ph&aacute;p Việt Nam - Trung Quốc c&oacute; c&aacute;c cơ chế đặc th&ugrave; cho hợp t&aacute;c đường sắt, đảm bảo an ninh năng lượng, đưa hợp t&aacute;c khoa học c&ocirc;ng nghệ trở th&agrave;nh điểm s&aacute;ng mới.</h2>\r\n<div class=\"detail-cmain\">\r\n<div class=\"detail-content afcbc-body\" itemprop=\"articleBody\" data-role=\"content\" data-io-article-url=\"https://thanhnien.vn/tong-bi-thu-chu-tich-nuoc-co-co-che-dac-thu-hop-tac-duong-sat-viet-trung-185260415180327989.htm\">\r\n<div data-check-position=\"body_start\">&nbsp;</div>\r\n<p data-id-seo=\"paragraphs-0\">Ng&agrave;y 15.4, tại Đại lễ đường Nh&acirc;n d&acirc;n, Bắc Kinh, trong khu&ocirc;n khổ chuyến thăm cấp nh&agrave; nước đến Trung Quốc,&nbsp;<a class=\"link-inline-content\" title=\"Tổng B&iacute; thư, Chủ tịch nước\" href=\"https://thanhnien.vn/tong-bi-thu-chu-tich-nuoc-de-nghi-viet-trung-uu-tien-cao-nhat-hop-tac-duong-sat-185260415131207665.htm\" data-rel=\"follow\">Tổng B&iacute; thư, Chủ tịch nước</a>&nbsp;T&ocirc; L&acirc;m đ&atilde; hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.</p>\r\n<figure class=\"VCSortableInPreviewMode\">\r\n<div><a class=\"detail-img-lightbox\" title=\"Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.\" href=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" target=\"_blank\" rel=\"noopener\" data-fancybox=\"img-lightbox\"><img id=\"img_217515974224154624\" class=\"lightbox-content\" style=\"max-width: 100%; height: auto;\" title=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 1.\" src=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" alt=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 1.\" width=\"2560\" height=\"1935\" loading=\"lazy\" data-author=\"\" data-original=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" data-id-seo=\"image-0\"></a></div>\r\n<figcaption class=\"PhotoCMS_Caption\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập ch&uacute; th&iacute;ch ảnh\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.</p>\r\n</figcaption>\r\n<div class=\"PhotoCMS_Author\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập t&aacute;c giả\">ẢNH: TTXVN</p>\r\n</div>\r\n</figure>\r\n<p data-id-seo=\"paragraphs-3\">Tại buổi hội kiến,Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m v&agrave; &ocirc;ng Triệu Lạc Tế đ&atilde; chia sẻ về t&igrave;nh h&igrave;nh mỗi đảng, mỗi nước v&agrave; hoạt động của hai cơ quan lập ph&aacute;p; vui mừng nhận thấy c&ugrave;ng với đ&agrave; ph&aacute;t triển t&iacute;ch cực của quan hệ hai đảng, hai nước v&agrave; những tiến triển tốt đẹp trong giao lưu, hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc.</p>\r\n<p data-id-seo=\"paragraphs-4\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m khẳng định chuyến thăm nhằm kế thừa v&agrave; tiếp nối chủ trương nhất qu&aacute;n, lựa chọn chiến lược v&agrave; ưu ti&ecirc;n h&agrave;ng đầu của Đảng, Nh&agrave; nước Việt Nam đối với quan hệ Việt - Trung; c&ugrave;ng c&aacute;c l&atilde;nh đạo Trung Quốc x&aacute;c lập tầm cao mới về gắn kết chiến lược giữa hai Đảng, hai nước trong kỷ nguy&ecirc;n ph&aacute;t triển mới.&nbsp;</p>\r\n<p data-id-seo=\"paragraphs-5\">&Ocirc;ng Triệu Lạc Tế nhấn mạnh Việt Nam v&agrave; Trung Quốc l&agrave; hai nước l&aacute;ng giềng x&atilde; hội chủ nghĩa c&oacute; truyền thống hữu nghị l&acirc;u đời, hai nước c&oacute; nhiều điểm tương đồng về chế độ ch&iacute;nh trị, con đường ph&aacute;t triển, truyền thống văn h&oacute;a x&atilde; hội. Trung Quốc ki&ecirc;n định ủng hộ Việt Nam x&acirc;y dựng th&agrave;nh c&ocirc;ng chủ nghĩa x&atilde; hội ph&ugrave; hợp với t&igrave;nh h&igrave;nh đất nước.</p>\r\n<p data-id-seo=\"paragraphs-6\">Nhấn mạnh tầm quan trọng của x&acirc;y dựng thể chế v&agrave; c&ocirc;ng t&aacute;c lập ph&aacute;p, Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m đề nghị l&agrave;m s&acirc;u sắc hơn nữa giao lưu, hợp t&aacute;c hữu nghị giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc. Tiếp tục triển khai hiệu quả cơ chế Ủy ban hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc.</p>\r\n<p data-id-seo=\"paragraphs-7\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n, nhất l&agrave; trong c&aacute;c lĩnh vực ngoại giao, quốc ph&ograve;ng, an ninh, thương mại, đầu tư, du lịch.&nbsp;</p>\r\n<p data-id-seo=\"paragraphs-8\">Trong đ&oacute;, trọng t&acirc;m l&agrave; th&uacute;c đẩy hợp t&aacute;c thương mại ph&aacute;t triển c&acirc;n bằng hơn, chuyển mạnh từ giao thương th&ocirc;ng thường sang gắn kết s&acirc;u sắc về li&ecirc;n kết kinh tế, chuỗi cung ứng, chuỗi sản xuất, tăng cường kết nối hạ tầng giao th&ocirc;ng, c&oacute; c&aacute;c cơ chế đặc th&ugrave; cho hợp t&aacute;c đường sắt, đảm bảo an ninh năng lượng, đưa hợp t&aacute;c khoa học c&ocirc;ng nghệ trở th&agrave;nh điểm s&aacute;ng mới...</p>\r\n<figure class=\"VCSortableInPreviewMode\">\r\n<div><a class=\"detail-img-lightbox\" title=\"Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n\" href=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" target=\"_blank\" rel=\"noopener\" data-fancybox=\"img-lightbox\"><img id=\"img_217515973448658944\" class=\"lightbox-content\" style=\"max-width: 100%; height: auto;\" title=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 2.\" src=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" alt=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 2.\" width=\"2560\" height=\"1671\" loading=\"lazy\" data-author=\"\" data-original=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" data-id-seo=\"image-1\"></a></div>\r\n<figcaption class=\"PhotoCMS_Caption\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập ch&uacute; th&iacute;ch ảnh\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n</p>\r\n</figcaption>\r\n<div class=\"PhotoCMS_Author\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập t&aacute;c giả\">ẢNH: TTXVN</p>\r\n</div>\r\n</figure>\r\n<div id=\"zone-l2srqb41\">\r\n<div id=\"share-l2srqbkq\"></div>\r\n</div>\r\n<h2 data-id-seo=\"h2-0\">Th&uacute;c đẩy kiểm so&aacute;t v&agrave; giải quyết tốt hơn bất đồng tr&ecirc;n biển</h2>\r\n<p data-id-seo=\"paragraphs-11\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng đề nghị Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc ph&aacute;t huy vai tr&ograve; của cơ quan d&acirc;n cử, đại diện &yacute; ch&iacute;, nguyện vọng của nh&acirc;n d&acirc;n trong việc tuy&ecirc;n truyền, tăng cường hiểu biết lẫn nhau; c&ugrave;ng th&uacute;c đẩy kiểm so&aacute;t v&agrave; giải quyết tốt hơn bất đồng tr&ecirc;n biển ph&ugrave; hợp với luật ph&aacute;p quốc tế, g&oacute;p phần kiến tạo m&ocirc;i trường h&ograve;a b&igrave;nh, ổn định cho sự ph&aacute;t triển của mỗi nước, giữ g&igrave;n t&igrave;nh cảm hữu nghị giữa hai b&ecirc;n.</p>\r\n<p data-id-seo=\"paragraphs-12\">Đ&aacute;nh gi&aacute; cao v&agrave; nhất tr&iacute; với những &yacute; kiến quan trọng của Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m về việc ph&aacute;t triển quan hệ hai đảng, hai nước, cũng như tăng cường giao lưu, hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc, &ocirc;ng Triệu Lạc Tế khẳng định Nh&acirc;n đại to&agrave;n quốc Trung Quốc sẵn s&agrave;ng c&ugrave;ng Quốc hội Việt Nam tăng cường hơn nữa giao lưu hữu nghị v&agrave; hợp t&aacute;c thiết thực.</p>\r\n<p data-id-seo=\"paragraphs-13\">&Ocirc;ng Triệu Lạc Tế cũng tr&acirc;n trọng mời Chủ tịch Quốc hội Trần Thanh Mẫn sớm thăm Trung Quốc, đồng chủ tr&igrave; kỳ họp lần thứ 2 ủy ban hợp t&aacute;c giữa hai cơ quan lập ph&aacute;p, qua đ&oacute;, t&iacute;ch cực chia sẻ kinh nghiệm về lập ph&aacute;p, gi&aacute;m s&aacute;t, c&ugrave;ng th&uacute;c đẩy kết nối chiến lược ph&aacute;t triển giữa hai nước, tăng cường hợp t&aacute;c văn h&oacute;a, gi&aacute;o dục, giao lưu nh&acirc;n d&acirc;n.</p>\r\n<p data-id-seo=\"paragraphs-14\">&Ocirc;ng Triệu Lạc Tế cũng đ&atilde; giới thiệu với Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m một số bộ luật mới đ&aacute;ng ch&uacute; &yacute; của Trung Quốc, bao gồm Ph&aacute;p điển về m&ocirc;i trường sinh th&aacute;i, luật Th&uacute;c đẩy đo&agrave;n kết, tiến bộ d&acirc;n tộc v&agrave; luật Quy hoạch ph&aacute;t triển quốc gia.</p>\r\n</div>\r\n</div>'),
(4, 'Laragon CMS', 'laragon-cms', '{\"en\":\"laragon-cms\",\"vi\":\"laragon-cms\"}', 'active', 'laragon cms', 'Một CMS hiện đại, siêu nhẹ, được thiết kế để đạt hiệu năng tối đa và mang lại trải nghiệm tuyệt vời cho lập trình viên.', 'Rising Star', '', '', '{\"id\":89,\"name\":\"cms-card-laragon-mark.jpg\",\"path\":\"2026/03/24/cms-card-laragon-mark.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', 4, 99, 'https://github.com/leokhoa/laragon/releases/download/8.6.1/laragon-wamp.exe', '2026-03-23 10:39:05', '2026-04-15 21:11:39', '[{\"pro_detail\":\"Cực nhanh (99/100)\"},{\"pro_detail\":\"Công nghệ hiện đại\"},{\"pro_detail\":\"Không có mã dư thừa\"}]', '[{\"cons_detail\":\"Cộng đồng còn mới\"},{\"cons_detail\":\"Ít giao diện hơn so với WordPress\"}]', 43, NULL, NULL, '<h2 class=\"detail-sapo\" data-role=\"sapo\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m đề nghị cơ quan lập ph&aacute;p Việt Nam - Trung Quốc c&oacute; c&aacute;c cơ chế đặc th&ugrave; cho hợp t&aacute;c đường sắt, đảm bảo an ninh năng lượng, đưa hợp t&aacute;c khoa học c&ocirc;ng nghệ trở th&agrave;nh điểm s&aacute;ng mới.</h2>\r\n<div class=\"detail-cmain\">\r\n<div class=\"detail-content afcbc-body\" itemprop=\"articleBody\" data-role=\"content\" data-io-article-url=\"https://thanhnien.vn/tong-bi-thu-chu-tich-nuoc-co-co-che-dac-thu-hop-tac-duong-sat-viet-trung-185260415180327989.htm\">\r\n<div data-check-position=\"body_start\">&nbsp;</div>\r\n<p data-id-seo=\"paragraphs-0\">Ng&agrave;y 15.4, tại Đại lễ đường Nh&acirc;n d&acirc;n, Bắc Kinh, trong khu&ocirc;n khổ chuyến thăm cấp nh&agrave; nước đến Trung Quốc,&nbsp;<a class=\"link-inline-content\" title=\"Tổng B&iacute; thư, Chủ tịch nước\" href=\"https://thanhnien.vn/tong-bi-thu-chu-tich-nuoc-de-nghi-viet-trung-uu-tien-cao-nhat-hop-tac-duong-sat-185260415131207665.htm\" data-rel=\"follow\">Tổng B&iacute; thư, Chủ tịch nước</a>&nbsp;T&ocirc; L&acirc;m đ&atilde; hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.</p>\r\n<figure class=\"VCSortableInPreviewMode\">\r\n<div><a class=\"detail-img-lightbox\" title=\"Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.\" href=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" target=\"_blank\" rel=\"noopener\" data-fancybox=\"img-lightbox\"><img id=\"img_217515974224154624\" class=\"lightbox-content\" style=\"max-width: 100%; height: auto;\" title=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 1.\" src=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" alt=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 1.\" width=\"2560\" height=\"1935\" loading=\"lazy\" data-author=\"\" data-original=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" data-id-seo=\"image-0\"></a></div>\r\n<figcaption class=\"PhotoCMS_Caption\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập ch&uacute; th&iacute;ch ảnh\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.</p>\r\n</figcaption>\r\n<div class=\"PhotoCMS_Author\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập t&aacute;c giả\">ẢNH: TTXVN</p>\r\n</div>\r\n</figure>\r\n<p data-id-seo=\"paragraphs-3\">Tại buổi hội kiến,Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m v&agrave; &ocirc;ng Triệu Lạc Tế đ&atilde; chia sẻ về t&igrave;nh h&igrave;nh mỗi đảng, mỗi nước v&agrave; hoạt động của hai cơ quan lập ph&aacute;p; vui mừng nhận thấy c&ugrave;ng với đ&agrave; ph&aacute;t triển t&iacute;ch cực của quan hệ hai đảng, hai nước v&agrave; những tiến triển tốt đẹp trong giao lưu, hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc.</p>\r\n<p data-id-seo=\"paragraphs-4\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m khẳng định chuyến thăm nhằm kế thừa v&agrave; tiếp nối chủ trương nhất qu&aacute;n, lựa chọn chiến lược v&agrave; ưu ti&ecirc;n h&agrave;ng đầu của Đảng, Nh&agrave; nước Việt Nam đối với quan hệ Việt - Trung; c&ugrave;ng c&aacute;c l&atilde;nh đạo Trung Quốc x&aacute;c lập tầm cao mới về gắn kết chiến lược giữa hai Đảng, hai nước trong kỷ nguy&ecirc;n ph&aacute;t triển mới.&nbsp;</p>\r\n<p data-id-seo=\"paragraphs-5\">&Ocirc;ng Triệu Lạc Tế nhấn mạnh Việt Nam v&agrave; Trung Quốc l&agrave; hai nước l&aacute;ng giềng x&atilde; hội chủ nghĩa c&oacute; truyền thống hữu nghị l&acirc;u đời, hai nước c&oacute; nhiều điểm tương đồng về chế độ ch&iacute;nh trị, con đường ph&aacute;t triển, truyền thống văn h&oacute;a x&atilde; hội. Trung Quốc ki&ecirc;n định ủng hộ Việt Nam x&acirc;y dựng th&agrave;nh c&ocirc;ng chủ nghĩa x&atilde; hội ph&ugrave; hợp với t&igrave;nh h&igrave;nh đất nước.</p>\r\n<p data-id-seo=\"paragraphs-6\">Nhấn mạnh tầm quan trọng của x&acirc;y dựng thể chế v&agrave; c&ocirc;ng t&aacute;c lập ph&aacute;p, Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m đề nghị l&agrave;m s&acirc;u sắc hơn nữa giao lưu, hợp t&aacute;c hữu nghị giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc. Tiếp tục triển khai hiệu quả cơ chế Ủy ban hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc.</p>\r\n<p data-id-seo=\"paragraphs-7\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n, nhất l&agrave; trong c&aacute;c lĩnh vực ngoại giao, quốc ph&ograve;ng, an ninh, thương mại, đầu tư, du lịch.&nbsp;</p>\r\n<p data-id-seo=\"paragraphs-8\">Trong đ&oacute;, trọng t&acirc;m l&agrave; th&uacute;c đẩy hợp t&aacute;c thương mại ph&aacute;t triển c&acirc;n bằng hơn, chuyển mạnh từ giao thương th&ocirc;ng thường sang gắn kết s&acirc;u sắc về li&ecirc;n kết kinh tế, chuỗi cung ứng, chuỗi sản xuất, tăng cường kết nối hạ tầng giao th&ocirc;ng, c&oacute; c&aacute;c cơ chế đặc th&ugrave; cho hợp t&aacute;c đường sắt, đảm bảo an ninh năng lượng, đưa hợp t&aacute;c khoa học c&ocirc;ng nghệ trở th&agrave;nh điểm s&aacute;ng mới...</p>\r\n<figure class=\"VCSortableInPreviewMode\">\r\n<div><a class=\"detail-img-lightbox\" title=\"Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n\" href=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" target=\"_blank\" rel=\"noopener\" data-fancybox=\"img-lightbox\"><img id=\"img_217515973448658944\" class=\"lightbox-content\" style=\"max-width: 100%; height: auto;\" title=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 2.\" src=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" alt=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 2.\" width=\"2560\" height=\"1671\" loading=\"lazy\" data-author=\"\" data-original=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" data-id-seo=\"image-1\"></a></div>\r\n<figcaption class=\"PhotoCMS_Caption\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập ch&uacute; th&iacute;ch ảnh\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n</p>\r\n</figcaption>\r\n<div class=\"PhotoCMS_Author\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập t&aacute;c giả\">ẢNH: TTXVN</p>\r\n</div>\r\n</figure>\r\n<div id=\"zone-l2srqb41\">\r\n<div id=\"share-l2srqbkq\"></div>\r\n</div>\r\n<h2 data-id-seo=\"h2-0\">Th&uacute;c đẩy kiểm so&aacute;t v&agrave; giải quyết tốt hơn bất đồng tr&ecirc;n biển</h2>\r\n<p data-id-seo=\"paragraphs-11\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng đề nghị Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc ph&aacute;t huy vai tr&ograve; của cơ quan d&acirc;n cử, đại diện &yacute; ch&iacute;, nguyện vọng của nh&acirc;n d&acirc;n trong việc tuy&ecirc;n truyền, tăng cường hiểu biết lẫn nhau; c&ugrave;ng th&uacute;c đẩy kiểm so&aacute;t v&agrave; giải quyết tốt hơn bất đồng tr&ecirc;n biển ph&ugrave; hợp với luật ph&aacute;p quốc tế, g&oacute;p phần kiến tạo m&ocirc;i trường h&ograve;a b&igrave;nh, ổn định cho sự ph&aacute;t triển của mỗi nước, giữ g&igrave;n t&igrave;nh cảm hữu nghị giữa hai b&ecirc;n.</p>\r\n<p data-id-seo=\"paragraphs-12\">Đ&aacute;nh gi&aacute; cao v&agrave; nhất tr&iacute; với những &yacute; kiến quan trọng của Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m về việc ph&aacute;t triển quan hệ hai đảng, hai nước, cũng như tăng cường giao lưu, hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc, &ocirc;ng Triệu Lạc Tế khẳng định Nh&acirc;n đại to&agrave;n quốc Trung Quốc sẵn s&agrave;ng c&ugrave;ng Quốc hội Việt Nam tăng cường hơn nữa giao lưu hữu nghị v&agrave; hợp t&aacute;c thiết thực.</p>\r\n<p data-id-seo=\"paragraphs-13\">&Ocirc;ng Triệu Lạc Tế cũng tr&acirc;n trọng mời Chủ tịch Quốc hội Trần Thanh Mẫn sớm thăm Trung Quốc, đồng chủ tr&igrave; kỳ họp lần thứ 2 ủy ban hợp t&aacute;c giữa hai cơ quan lập ph&aacute;p, qua đ&oacute;, t&iacute;ch cực chia sẻ kinh nghiệm về lập ph&aacute;p, gi&aacute;m s&aacute;t, c&ugrave;ng th&uacute;c đẩy kết nối chiến lược ph&aacute;t triển giữa hai nước, tăng cường hợp t&aacute;c văn h&oacute;a, gi&aacute;o dục, giao lưu nh&acirc;n d&acirc;n.</p>\r\n<p data-id-seo=\"paragraphs-14\">&Ocirc;ng Triệu Lạc Tế cũng đ&atilde; giới thiệu với Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m một số bộ luật mới đ&aacute;ng ch&uacute; &yacute; của Trung Quốc, bao gồm Ph&aacute;p điển về m&ocirc;i trường sinh th&aacute;i, luật Th&uacute;c đẩy đo&agrave;n kết, tiến bộ d&acirc;n tộc v&agrave; luật Quy hoạch ph&aacute;t triển quốc gia.</p>\r\n</div>\r\n</div>'),
(5, 'Drupal', 'drupal', '{\"en\":\"drupal\",\"vi\":\"drupal\"}', 'active', 'drupal', 'CMS mạnh mẽ dành cho các website doanh nghiệp phức tạp, lưu lượng truy cập cao.', '', '', '', '{\"id\":126,\"name\":\"d.jpg\",\"path\":\"2026/03/31/d.jpg\",\"sizes\":[{\"name\":\"thumbnail\",\"width\":\"250\",\"height\":\"250\"},{\"name\":\"medium\",\"width\":\"600\",\"height\":\"600\"},{\"name\":\"large\",\"width\":\"1000\",\"height\":\"1000\"}],\"webp\":1}', 4, 50, '', '2026-03-23 10:53:17', '2026-04-15 21:11:45', '[{\"pro_detail\":\"Khả năng mở rộng cao\"},{\"pro_detail\":\"Bảo mật mạnh\"},{\"pro_detail\":\"Hỗ trợ kiểu nội dung tùy chỉnh\"}]', '[{\"cons_detail\":\"Khó học\"},{\"cons_detail\":\"Cần có developer để triển khai\"},{\"cons_detail\":\"Tốn nhiều tài nguyên\"}]', 1, NULL, NULL, '<h2 class=\"detail-sapo\" data-role=\"sapo\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m đề nghị cơ quan lập ph&aacute;p Việt Nam - Trung Quốc c&oacute; c&aacute;c cơ chế đặc th&ugrave; cho hợp t&aacute;c đường sắt, đảm bảo an ninh năng lượng, đưa hợp t&aacute;c khoa học c&ocirc;ng nghệ trở th&agrave;nh điểm s&aacute;ng mới.</h2>\r\n<div class=\"detail-cmain\">\r\n<div class=\"detail-content afcbc-body\" itemprop=\"articleBody\" data-role=\"content\" data-io-article-url=\"https://thanhnien.vn/tong-bi-thu-chu-tich-nuoc-co-co-che-dac-thu-hop-tac-duong-sat-viet-trung-185260415180327989.htm\">\r\n<div data-check-position=\"body_start\">&nbsp;</div>\r\n<p data-id-seo=\"paragraphs-0\">Ng&agrave;y 15.4, tại Đại lễ đường Nh&acirc;n d&acirc;n, Bắc Kinh, trong khu&ocirc;n khổ chuyến thăm cấp nh&agrave; nước đến Trung Quốc,&nbsp;<a class=\"link-inline-content\" title=\"Tổng B&iacute; thư, Chủ tịch nước\" href=\"https://thanhnien.vn/tong-bi-thu-chu-tich-nuoc-de-nghi-viet-trung-uu-tien-cao-nhat-hop-tac-duong-sat-185260415131207665.htm\" data-rel=\"follow\">Tổng B&iacute; thư, Chủ tịch nước</a>&nbsp;T&ocirc; L&acirc;m đ&atilde; hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.</p>\r\n<figure class=\"VCSortableInPreviewMode\">\r\n<div><a class=\"detail-img-lightbox\" title=\"Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.\" href=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" target=\"_blank\" rel=\"noopener\" data-fancybox=\"img-lightbox\"><img id=\"img_217515974224154624\" class=\"lightbox-content\" style=\"max-width: 100%; height: auto;\" title=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 1.\" src=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" alt=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 1.\" width=\"2560\" height=\"1935\" loading=\"lazy\" data-author=\"\" data-original=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-1-1776250896938868996040.jpg\" data-id-seo=\"image-0\"></a></div>\r\n<figcaption class=\"PhotoCMS_Caption\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập ch&uacute; th&iacute;ch ảnh\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m hội kiến Ủy vi&ecirc;n trưởng Ủy ban Thường vụ Đại hội Đại biểu nh&acirc;n d&acirc;n to&agrave;n quốc Trung Quốc Triệu Lạc Tế.</p>\r\n</figcaption>\r\n<div class=\"PhotoCMS_Author\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập t&aacute;c giả\">ẢNH: TTXVN</p>\r\n</div>\r\n</figure>\r\n<p data-id-seo=\"paragraphs-3\">Tại buổi hội kiến,Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m v&agrave; &ocirc;ng Triệu Lạc Tế đ&atilde; chia sẻ về t&igrave;nh h&igrave;nh mỗi đảng, mỗi nước v&agrave; hoạt động của hai cơ quan lập ph&aacute;p; vui mừng nhận thấy c&ugrave;ng với đ&agrave; ph&aacute;t triển t&iacute;ch cực của quan hệ hai đảng, hai nước v&agrave; những tiến triển tốt đẹp trong giao lưu, hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc.</p>\r\n<p data-id-seo=\"paragraphs-4\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m khẳng định chuyến thăm nhằm kế thừa v&agrave; tiếp nối chủ trương nhất qu&aacute;n, lựa chọn chiến lược v&agrave; ưu ti&ecirc;n h&agrave;ng đầu của Đảng, Nh&agrave; nước Việt Nam đối với quan hệ Việt - Trung; c&ugrave;ng c&aacute;c l&atilde;nh đạo Trung Quốc x&aacute;c lập tầm cao mới về gắn kết chiến lược giữa hai Đảng, hai nước trong kỷ nguy&ecirc;n ph&aacute;t triển mới.&nbsp;</p>\r\n<p data-id-seo=\"paragraphs-5\">&Ocirc;ng Triệu Lạc Tế nhấn mạnh Việt Nam v&agrave; Trung Quốc l&agrave; hai nước l&aacute;ng giềng x&atilde; hội chủ nghĩa c&oacute; truyền thống hữu nghị l&acirc;u đời, hai nước c&oacute; nhiều điểm tương đồng về chế độ ch&iacute;nh trị, con đường ph&aacute;t triển, truyền thống văn h&oacute;a x&atilde; hội. Trung Quốc ki&ecirc;n định ủng hộ Việt Nam x&acirc;y dựng th&agrave;nh c&ocirc;ng chủ nghĩa x&atilde; hội ph&ugrave; hợp với t&igrave;nh h&igrave;nh đất nước.</p>\r\n<p data-id-seo=\"paragraphs-6\">Nhấn mạnh tầm quan trọng của x&acirc;y dựng thể chế v&agrave; c&ocirc;ng t&aacute;c lập ph&aacute;p, Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m đề nghị l&agrave;m s&acirc;u sắc hơn nữa giao lưu, hợp t&aacute;c hữu nghị giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc. Tiếp tục triển khai hiệu quả cơ chế Ủy ban hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc.</p>\r\n<p data-id-seo=\"paragraphs-7\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n, nhất l&agrave; trong c&aacute;c lĩnh vực ngoại giao, quốc ph&ograve;ng, an ninh, thương mại, đầu tư, du lịch.&nbsp;</p>\r\n<p data-id-seo=\"paragraphs-8\">Trong đ&oacute;, trọng t&acirc;m l&agrave; th&uacute;c đẩy hợp t&aacute;c thương mại ph&aacute;t triển c&acirc;n bằng hơn, chuyển mạnh từ giao thương th&ocirc;ng thường sang gắn kết s&acirc;u sắc về li&ecirc;n kết kinh tế, chuỗi cung ứng, chuỗi sản xuất, tăng cường kết nối hạ tầng giao th&ocirc;ng, c&oacute; c&aacute;c cơ chế đặc th&ugrave; cho hợp t&aacute;c đường sắt, đảm bảo an ninh năng lượng, đưa hợp t&aacute;c khoa học c&ocirc;ng nghệ trở th&agrave;nh điểm s&aacute;ng mới...</p>\r\n<figure class=\"VCSortableInPreviewMode\">\r\n<div><a class=\"detail-img-lightbox\" title=\"Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n\" href=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" target=\"_blank\" rel=\"noopener\" data-fancybox=\"img-lightbox\"><img id=\"img_217515973448658944\" class=\"lightbox-content\" style=\"max-width: 100%; height: auto;\" title=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 2.\" src=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" alt=\"Tổng B&iacute; thư, Chủ tịch nước: C&oacute; cơ chế đặc th&ugrave; hợp t&aacute;c đường sắt Việt-Trung- Ảnh 2.\" width=\"2560\" height=\"1671\" loading=\"lazy\" data-author=\"\" data-original=\"https://images2.thanhnien.vn/528068263637045248/2026/4/15/tong-bi-thu-chu-tich-nuoc-tham-trung-quoc-hanh-trinh-do-2-17762508968811920219999.jpg\" data-id-seo=\"image-1\"></a></div>\r\n<figcaption class=\"PhotoCMS_Caption\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập ch&uacute; th&iacute;ch ảnh\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng mong muốn cơ quan lập hai nước ph&aacute;t huy mạnh mẽ vai tr&ograve; x&acirc;y dựng ph&aacute;p luật v&agrave; gi&aacute;m s&aacute;t, g&oacute;p phần tiếp tục mở rộng v&agrave; n&acirc;ng cao hiệu quả hợp t&aacute;c thực chất giữa hai b&ecirc;n</p>\r\n</figcaption>\r\n<div class=\"PhotoCMS_Author\">\r\n<p class=\"NLPlaceholderShow\" data-placeholder=\"Nhập t&aacute;c giả\">ẢNH: TTXVN</p>\r\n</div>\r\n</figure>\r\n<div id=\"zone-l2srqb41\">\r\n<div id=\"share-l2srqbkq\"></div>\r\n</div>\r\n<h2 data-id-seo=\"h2-0\">Th&uacute;c đẩy kiểm so&aacute;t v&agrave; giải quyết tốt hơn bất đồng tr&ecirc;n biển</h2>\r\n<p data-id-seo=\"paragraphs-11\">Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m cũng đề nghị Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc ph&aacute;t huy vai tr&ograve; của cơ quan d&acirc;n cử, đại diện &yacute; ch&iacute;, nguyện vọng của nh&acirc;n d&acirc;n trong việc tuy&ecirc;n truyền, tăng cường hiểu biết lẫn nhau; c&ugrave;ng th&uacute;c đẩy kiểm so&aacute;t v&agrave; giải quyết tốt hơn bất đồng tr&ecirc;n biển ph&ugrave; hợp với luật ph&aacute;p quốc tế, g&oacute;p phần kiến tạo m&ocirc;i trường h&ograve;a b&igrave;nh, ổn định cho sự ph&aacute;t triển của mỗi nước, giữ g&igrave;n t&igrave;nh cảm hữu nghị giữa hai b&ecirc;n.</p>\r\n<p data-id-seo=\"paragraphs-12\">Đ&aacute;nh gi&aacute; cao v&agrave; nhất tr&iacute; với những &yacute; kiến quan trọng của Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m về việc ph&aacute;t triển quan hệ hai đảng, hai nước, cũng như tăng cường giao lưu, hợp t&aacute;c giữa Quốc hội Việt Nam v&agrave; Nh&acirc;n đại to&agrave;n quốc Trung Quốc, &ocirc;ng Triệu Lạc Tế khẳng định Nh&acirc;n đại to&agrave;n quốc Trung Quốc sẵn s&agrave;ng c&ugrave;ng Quốc hội Việt Nam tăng cường hơn nữa giao lưu hữu nghị v&agrave; hợp t&aacute;c thiết thực.</p>\r\n<p data-id-seo=\"paragraphs-13\">&Ocirc;ng Triệu Lạc Tế cũng tr&acirc;n trọng mời Chủ tịch Quốc hội Trần Thanh Mẫn sớm thăm Trung Quốc, đồng chủ tr&igrave; kỳ họp lần thứ 2 ủy ban hợp t&aacute;c giữa hai cơ quan lập ph&aacute;p, qua đ&oacute;, t&iacute;ch cực chia sẻ kinh nghiệm về lập ph&aacute;p, gi&aacute;m s&aacute;t, c&ugrave;ng th&uacute;c đẩy kết nối chiến lược ph&aacute;t triển giữa hai nước, tăng cường hợp t&aacute;c văn h&oacute;a, gi&aacute;o dục, giao lưu nh&acirc;n d&acirc;n.</p>\r\n<p data-id-seo=\"paragraphs-14\">&Ocirc;ng Triệu Lạc Tế cũng đ&atilde; giới thiệu với Tổng B&iacute; thư, Chủ tịch nước T&ocirc; L&acirc;m một số bộ luật mới đ&aacute;ng ch&uacute; &yacute; của Trung Quốc, bao gồm Ph&aacute;p điển về m&ocirc;i trường sinh th&aacute;i, luật Th&uacute;c đẩy đo&agrave;n kết, tiến bộ d&acirc;n tộc v&agrave; luật Quy hoạch ph&aacute;t triển quốc gia.</p>\r\n</div>\r\n</div>');

