CREATE TABLE `fast_storage` (
  `id` int(11) NOT NULL,
  `name` varchar(50) CHARACTER SET ascii COLLATE ascii_bin NOT NULL COMMENT 'key name \r\n(max 50)',
  `scope` varchar(100) CHARACTER SET ascii COLLATE ascii_bin NOT NULL COMMENT 'Max 100 | Allows: a-zA-Z0-9_-/ (plugins/ecommerce/payments)',
  `value` longtext DEFAULT NULL COMMENT 'serialize($value) - default language'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Universal storage with perfect type safety';

