(78, 'Introduction', 'introduction', '', 'active', '', NULL, '<div><!-- Introduction Tab Content -->\r\n<div class=\"mb-12 sm:px-0\">\r\n<div class=\"flex md:grid md:grid-cols-3 gap-4 md:gap-6 mb-12 overflow-x-auto md:overflow-x-visible pb-4 md:pb-0 scrollbar-hide -mx-4 px-4 sm:mx-0 sm:px-0\">\r\n<div class=\"group rounded-home-lg transition-all duration-300 border-transparent p-[1.5px] bg-gradient-to-r from-home-accent to-home-primary md:border-gray-200 md:border md:bg-none md:p-0 md:hover:border-transparent md:hover:p-[1px] md:hover:bg-gradient-to-r md:hover:from-home-accent md:hover:to-home-primary flex-shrink-0 w-[200px] md:w-full cursor-pointer\">\r\n<div class=\"group relative w-full h-full bg-white md:border md:border-gray-200 rounded-home-lg p-4 md:p-6 lg:p-2 xl:p-6 hover:shadow-lg transition-all duration-200 overflow-hidden\">\r\n<div class=\"absolute -bottom-[36px] -right-[60px] opacity-10 md:group-hover:text-home-primary md:group-hover:opacity-30 md:group-hover:scale-110 transition-all duration-300 ease-out rotate-[-19.82deg] md:group-hover:-translate-y-8\"><img class=\"lucide lucide-notebook-pen-icon lucide-notebook-pen\" style=\"max-width: 100%; height: auto;\" title=\"vector.jpg\" src=\"https://laragon.net/content/uploads/2026/03/31/vector.jpg\" alt=\"vector.jpg\"></div>\r\n<h3 class=\"font-plus text-base md:text-xl text-gray-900 mb-2 font-plus\">Quick Start</h3>\r\n<p class=\"text-gray-600 mb-4 flex-1 text-sm md:text-base font-plus\">Install and run your first app in 5 mins.</p>\r\n<!-- Go Link --> <span class=\"inline-flex items-center gap-2 text-home-primary font-medium opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity duration-200 h-6 text-md md:text-md\"> Go &rarr;</span></div>\r\n</div>\r\n<!-- Workflows Card -->\r\n<div class=\"group rounded-home-lg transition-all duration-300 border-transparent p-[1.5px] bg-gradient-to-r from-home-accent to-home-primary md:border-gray-200 md:border md:bg-none md:p-0 md:hover:border-transparent md:hover:p-[1px] md:hover:bg-gradient-to-r md:hover:from-home-accent md:hover:to-home-primary flex-shrink-0 w-[200px] md:w-full cursor-pointer\">\r\n<div class=\"group relative w-full h-full bg-white md:border md:border-gray-200 rounded-home-lg p-4 md:p-6 lg:p-2 xl:p-6 hover:shadow-lg transition-all duration-200 overflow-hidden\">\r\n<div class=\"absolute -bottom-[36px] -right-[60px] opacity-10 md:group-hover:text-home-primary md:group-hover:opacity-30 md:group-hover:scale-110 transition-all duration-300 ease-out rotate-[-19.82deg] md:group-hover:-translate-y-8\"><img class=\"lucide lucide-notebook-pen-icon lucide-notebook-pen\" style=\"max-width: 100%; height: auto;\" title=\"vector.jpg\" src=\"https://laragon.net/content/uploads/2026/03/31/vector.jpg\" alt=\"vector.jpg\"></div>\r\n<h3 class=\"text-base md:text-xl text-gray-900 mb-2 font-plus\">Workflows</h3>\r\n<p class=\"text-gray-600 mb-4 flex-1 text-sm md:text-base font-plus\">Best practices for Laravel, WP, and more.</p>\r\n<!-- Go Link --> <span class=\"inline-flex items-center gap-2 text-home-primary font-medium opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity duration-200 h-6 text-md md:text-md\"> Go &rarr;</span></div>\r\n</div>\r\n<!-- FAQs Card -->\r\n<div class=\"group rounded-home-lg transition-all duration-300 border-transparent p-[1.5px] bg-gradient-to-r from-home-accent to-home-primary md:border-gray-200 md:border md:bg-none md:p-0 md:hover:border-transparent md:hover:p-[1px] md:hover:bg-gradient-to-r md:hover:from-home-accent md:hover:to-home-primary flex-shrink-0 w-[200px] md:w-full cursor-pointer\">\r\n<div class=\"group relative w-full h-full bg-white md:border md:border-gray-200 rounded-home-lg p-4 md:p-6 lg:p-2 xl:p-6 hover:shadow-lg transition-all duration-200 overflow-hidden\">\r\n<div class=\"absolute -bottom-[36px] -right-[60px] opacity-10 md:group-hover:text-home-primary md:group-hover:opacity-30 md:group-hover:scale-110 transition-all duration-300 ease-out rotate-[-19.82deg] md:group-hover:-translate-y-8\"><img class=\"lucide lucide-notebook-pen-icon lucide-notebook-pen\" style=\"max-width: 100%; height: auto;\" title=\"vector.jpg\" src=\"https://laragon.net/content/uploads/2026/03/31/vector.jpg\" alt=\"vector.jpg\"></div>\r\n<h3 class=\"font-plus text-base md:text-xl text-gray-900 mb-2 font-plus\">FAQs</h3>\r\n<p class=\"text-gray-600 mb-4 flex-1 text-sm md:text-base font-plus\">Solutions to common issues</p>\r\n<!-- Go Link --> <span class=\"inline-flex items-center gap-2 text-home-primary font-medium opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity duration-200 h-6 text-md md:text-md font-plus\"> Go &rarr;</span></div>\r\n</div>\r\n</div>\r\n<!-- Info Box -->\r\n<div class=\"border-2 border-home-primary rounded-home-lg p-4 sm:p-6 bg-home-surface-light\">\r\n<div class=\"flex flex-row gap-3 sm:gap-4\">\r\n<div class=\"flex items-start flex-shrink-0\"><img style=\"max-width: 100%; height: auto;\" title=\"iconpen.png\" src=\"https://laragon.net/content/uploads/2026/03/28/iconpen.png\" alt=\"iconpen.png\"></div>\r\n<div class=\"text-left\">\r\n<h4 class=\"font-plus text-[16px] sm:text-lg font-semibold text-home-heading mb-1 sm:mb-2 leading-6\" style=\"font-family: \'Plus Jakarta Sans\', sans-serif;\">How to read this documentation</h4>\r\n<p class=\"text-xs sm:text-base text-gray-700 leading-relaxed font-plus\">This guide is structured by \"Workflows\". Instead of just listing features, we show you <span class=\"text-home-heading font-semibold\">how to get things done.</span> Use the sidebar to navigate topics.</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '', '', '2026-03-28 13:30:43', '2026-04-01 10:51:01', 'Everything you need to know to get started, manage projects, and optimize your development workflow.', 'usage_guide', 0, 0, 0.00),
(79, 'Installation &amp;amp; Setup', 'installation-setup', '', 'active', '', NULL, '<div class=\"\"><!-- Installation Tab Content -->\r\n<div class=\"mb-12 sm:px-0\">\r\n<div class=\"relative mb-16\">\r\n<div class=\"absolute left-6 top-0 bottom-0 w-0.5 bg-gradient-to-b from-home-accent to-home-primary\">&nbsp;</div>\r\n<!-- Step 1 -->\r\n<div class=\"relative flex gap-6 mb-8\">\r\n<div class=\"flex-shrink-0 relative z-10\">\r\n<div class=\"w-12 h-12 rounded-full bg-gradient-to-br from-home-accent to-home-primary flex items-center justify-center text-white font-bold text-lg shadow-lg\">1</div>\r\n</div>\r\n<div class=\"flex-1 rounded-[24px] border border-gray-200 overflow-hidden shadow-[0_2.667px_8px_0_rgba(43,140,238,0.05)]\">\r\n<h3 class=\"font-plus text-xl font-semibold bg-home-surface text-gray-900 p-6\">Download Laragon</h3>\r\n<p class=\"text-sm sm:text-base text-gray-600 leading-relaxed p-4 sm:p-4 font-plus\">Get the latest version from the official website. Choose \"Full\" for a complete stack (Apache, MySQL, PHP, Node.js) or \"Lite\" for a minimal setup.</p>\r\n</div>\r\n</div>\r\n<!-- Step 2 -->\r\n<div class=\"relative flex gap-6 mb-8\">\r\n<div class=\"flex-shrink-0 relative z-10\">\r\n<div class=\"w-12 h-12 rounded-full bg-gradient-to-br from-home-accent to-home-primary flex items-center justify-center text-white font-bold text-lg shadow-lg\">2</div>\r\n</div>\r\n<div class=\"flex-1 rounded-[24px] border border-gray-200 overflow-hidden shadow-[0_2.667px_8px_0_rgba(43,140,238,0.05)]\">\r\n<h3 class=\"font-plus text-xl font-semibold bg-home-surface text-gray-900 p-6\">Run Installer</h3>\r\n<p class=\"text-sm sm:text-base text-gray-600 leading-relaxed p-4 sm:p-4 font-plus\">Run the setup file and click Next. Choose an installation location (Avoid paths with special characters).</p>\r\n</div>\r\n</div>\r\n<!-- Step 3 -->\r\n<div class=\"relative flex gap-6\">\r\n<div class=\"flex-shrink-0\">\r\n<div class=\"w-12 h-12 rounded-full bg-gradient-to-br from-home-accent to-home-primary flex items-center justify-center text-white font-bold text-lg shadow-lg\">3</div>\r\n</div>\r\n<div class=\"flex-1 rounded-[24px] border border-gray-200 overflow-hidden shadow-[0_2.667px_8px_0_rgba(43,140,238,0.05)]\">\r\n<h3 class=\"font-plus text-xl font-semibold bg-home-surface text-gray-900 p-6\">Configure Options</h3>\r\n<p class=\"text-sm sm:text-base text-gray-600 leading-relaxed p-4 sm:p-4 font-plus\">Select \"Run Laragon When Windows Starts\" for convenience and \"Auto Virtual Hosts\" to get pretty URLs (e.g., app.test) automatically.</p>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- Important Installation Notes Section -->\r\n<div class=\"mb-8 sm:mb-12\">\r\n<h2 class=\"mb-6 sm:mb-12 text-home-heading font-medium sm:font-bold text-3xl sm:text-[48px] lg:text-[44px] xl:text-[62px] leading-tight sm:leading-[60px] lg:leading-[80px] font-plus\">Important Installation Notes</h2>\r\n<!-- Cards Grid -->\r\n<div class=\"grid grid-cols-2 gap-3 sm:gap-6\"><!-- System Requirements Card -->\r\n<div class=\"bg-white border border-gray-200 rounded-home-lg p-3 sm:p-4 md:p-6 hover:shadow-lg transition-shadow\">\r\n<div class=\"flex flex-col gap-2 sm:gap-3 md:gap-4\">\r\n<div class=\"flex flex-col xl:flex-row items-start gap-3 sm:gap-3 md:gap-4\"><img style=\"max-width: 100%; height: auto;\" title=\"frame-29.png\" src=\"https://laragon.net/content/uploads/2026/03/28/frame-29.png\" alt=\"frame-29.png\">\r\n<h3 class=\"mb-0 font-plus text-home-heading text-xl sm:text-base md:text-xl lg:text-xl xl:text-2xl leading-tight sm:leading-normal md:leading-[36px]\">System Requirements</h3>\r\n</div>\r\n<p class=\"text-home-body font-plus text-xs sm:text-[13px] md:text-sm leading-relaxed sm:leading-relaxed md:leading-[21px]\">Windows 7/8/10/11 (64-bit). Extremely low resource usage.</p>\r\n</div>\r\n</div>\r\n<!-- Full vs Lite Card -->\r\n<div class=\"bg-white border border-gray-200 rounded-home-lg p-3 sm:p-4 md:p-6 hover:shadow-lg transition-shadow\">\r\n<div class=\"flex flex-col gap-3 sm:gap-3 md:gap-4\">\r\n<div class=\"flex flex-col xl:flex-row items-start gap-3 sm:gap-3 md:gap-4\">\r\n<div class=\"flex-shrink-0 w-8 h-8 sm:w-10 sm:h-10 md:w-12 md:h-12 rounded-home-md bg-home-surface-light flex items-center justify-center\"><img style=\"max-width: 100%; height: auto;\" title=\"frame-29-1.png\" src=\"https://laragon.net/content/uploads/2026/03/28/frame-29-1.png\" alt=\"frame-29-1.png\"></div>\r\n<h3 class=\"mb-0 text-home-heading text-xl sm:text-base md:text-xl lg:text-2xl leading-tight sm:leading-normal md:leading-[36px] font-plus\">Full vs Lite</h3>\r\n</div>\r\n<p class=\"text-home-body text-xs sm:text-[13px] md:text-sm leading-relaxed sm:leading-relaxed md:leading-[21px] font-plus\">Use Full for instant setup. Use Lite if you prefer customizing tools yourself.</p>\r\n</div>\r\n</div>\r\n<!-- Location Card -->\r\n<div class=\"bg-white border border-gray-200 rounded-home-lg p-3 sm:p-4 md:p-6 hover:shadow-lg transition-shadow\">\r\n<div class=\"flex flex-col gap-2 sm:gap-3 md:gap-4\">\r\n<div class=\"flex flex-col xl:flex-row items-start gap-2 sm:gap-3 md:gap-4\">\r\n<div class=\"flex-shrink-0 w-8 h-8 sm:w-10 sm:h-10 md:w-12 md:h-12 rounded-home-md bg-home-surface-light flex items-center justify-center\"><img style=\"max-width: 100%; height: auto;\" title=\"frame-29-2.png\" src=\"https://laragon.net/content/uploads/2026/03/28/frame-29-2.png\" alt=\"frame-29-2.png\"></div>\r\n<h3 class=\"mb-0 text-home-heading text-xl sm:text-base md:text-xl lg:text-2xl leading-tight sm:leading-normal md:leading-[36px] font-plus\">Location</h3>\r\n</div>\r\n<p class=\"text-home-body text-xs sm:text-[13px] md:text-sm leading-relaxed sm:leading-relaxed md:leading-[21px] font-plus\">Install anywhere, but avoid spaces or special characters in the path.</p>\r\n</div>\r\n</div>\r\n<!-- Virtual Hosts Card -->\r\n<div class=\"bg-white border border-gray-200 rounded-home-lg p-3 sm:p-4 md:p-6 hover:shadow-lg transition-shadow\">\r\n<div class=\"flex flex-col gap-2 sm:gap-3 md:gap-4\">\r\n<div class=\"flex flex-col xl:flex-row items-start gap-3 sm:gap-3 md:gap-4\">\r\n<div class=\"flex-shrink-0 w-8 h-8 sm:w-10 sm:h-10 md:w-12 md:h-12 rounded-home-md bg-home-surface-light flex items-center justify-center\"><img style=\"max-width: 100%; height: auto;\" title=\"frame-29-3.png\" src=\"https://laragon.net/content/uploads/2026/03/28/frame-29-3.png\" alt=\"frame-29-3.png\"></div>\r\n<h3 class=\"mb-0 text-home-heading text-xl sm:text-base md:text-xl lg:text-2xl leading-tight sm:leading-normal md:leading-[36px] font-plus\">Virtual Hosts</h3>\r\n</div>\r\n<p class=\"text-home-body text-xs sm:text-[13px] md:text-sm leading-relaxed sm:leading-relaxed md:leading-[21px] font-plus\">Enabled by default. Makes accessing local projects much easier.</p>\r\n</div>\r\n</div>\r\n<!-- Auto-start Card -->\r\n<div class=\"bg-white border border-gray-200 rounded-home-lg p-3 sm:p-4 md:p-6 hover:shadow-lg transition-shadow\">\r\n<div class=\"flex flex-col gap-2 sm:gap-3 md:gap-4\">\r\n<div class=\"flex flex-col xl:flex-row items-start gap-3 sm:gap-3 md:gap-4\">\r\n<div class=\"flex-shrink-0 w-8 h-8 sm:w-10 sm:h-10 md:w-12 md:h-12 rounded-home-md bg-home-surface-light flex items-center justify-center\"><img style=\"max-width: 100%; height: auto;\" title=\"frame-29-5.png\" src=\"https://laragon.net/content/uploads/2026/03/28/frame-29-5.png\" alt=\"frame-29-5.png\"></div>\r\n<h3 class=\"mb-0 text-home-heading text-xl sm:text-base md:text-xl lg:text-2xl leading-tight sm:leading-normal md:leading-[36px] font-plus  \">Auto-start</h3>\r\n</div>\r\n<p class=\"text-home-body text-xs sm:text-[13px] md:text-sm leading-relaxed sm:leading-relaxed md:leading-[21px] font-plus\">Optional. Starts Laragon automatically when Windows boots.</p>\r\n</div>\r\n</div>\r\n<!-- MySQL Backup Card -->\r\n<div class=\"bg-white border border-gray-200 rounded-home-lg p-3 sm:p-4 md:p-6 hover:shadow-lg transition-shadow\">\r\n<div class=\"flex flex-col gap-3 sm:gap-3 md:gap-4\">\r\n<div class=\"flex flex-col xl:flex-row items-start gap-2 sm:gap-3 md:gap-4\">\r\n<div class=\"flex-shrink-0 w-8 h-8 sm:w-10 sm:h-10 md:w-12 md:h-12 rounded-home-md bg-home-surface-light flex items-center justify-center\"><img style=\"max-width: 100%; height: auto;\" title=\"frame-29-4.png\" src=\"https://laragon.net/content/uploads/2026/03/28/frame-29-4.png\" alt=\"frame-29-4.png\"></div>\r\n<h3 class=\"mb-0 text-home-heading text-xl sm:text-base md:text-xl lg:text-2xl leading-tight sm:leading-normal md:leading-[36px] font-plus\">MySQL Backup</h3>\r\n</div>\r\n<p class=\"text-home-body text-xs sm:text-[13px] md:text-sm leading-relaxed sm:leading-relaxed md:leading-[21px] font-plus\">Laragon includes auto-backup for data safety.</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '', '', '2026-03-28 13:31:42', '2026-04-01 10:56:31', '', 'usage_guide', 0, 0, 0.00),
(80, 'Real-world Workflows', 'real-world-workflows', '', 'active', '', NULL, '<div class=\"\"><!-- Workflows Tab Content -->\r\n<div class=\"mb-12 sm:px-0\"><!-- Section 1: Create a New Laravel Project -->\r\n<div class=\"mb-6 sm:mb-8 bg-gradient-to-r from-[#FFF5F5] to-[#FFE5E5] border border-[#FFE5E5]\">\r\n<div class=\"flex items-center self-stretch p-4 sm:p-6 gap-3 sm:gap-4\">\r\n<div class=\"flex-shrink-0 w-10 h-10 sm:w-12 sm:h-12 rounded-home-md bg-[#FFE5E5] flex items-center justify-center\"><img style=\"max-width: 100%; height: auto;\" title=\"frame-29-6.png\" src=\"https://laragon.net/content/uploads/2026/03/28/frame-29-6.png\" alt=\"frame-29-6.png\"></div>\r\n<h2 class=\"font-plus text-xl sm:text-2xl lg:text-2xl font-semibold text-gray-900\">Create a New Laravel Project</h2>\r\n</div>\r\n</div>\r\n<div class=\"px-4 sm:px-6 pb-8  space-y-6\">\r\n<div class=\"flex items-start gap-2 sm:gap-3\">\r\n<p class=\"text-sm sm:text-base text-gray-700 leading-relaxed font-plus\">Menu &gt; Quick app &gt; Laravel</p>\r\n</div>\r\n<div class=\"flex items-start gap-2 sm:gap-3\">\r\n<p class=\"text-sm sm:text-base text-gray-700 leading-relaxed font-plus\">Name your project (e.g., \"my-api\")</p>\r\n</div>\r\n<div class=\"flex items-start gap-2 sm:gap-3\">\r\n<p class=\"text-sm sm:text-base text-gray-700 leading-relaxed font-plus\">Wait for Composer to finish. Access at http://my-api.test</p>\r\n</div>\r\n</div>\r\n<!-- Terminal Output -->\r\n<div class=\"w-full lg:px-4 mb-8 sm:mb-12 pb-2\"><img class=\"w-full h-auto\" style=\"max-width: 100%; height: auto;\" src=\"https://laragon.net/assets/images/usegade.png\" alt=\"\"></div>\r\n<!-- Section 2: Migrate from XAMPP to Laragon -->\r\n<div class=\"mb-6 sm:mb-8 bg-gradient-to-r from-[#FFF7ED] to-[#FFF7ED] border border-[#FFF7ED]\">\r\n<div class=\"flex items-center self-stretch p-4 sm:p-6 gap-3 sm:gap-4\">\r\n<div class=\"flex-shrink-0 w-10 h-10 sm:w-12 sm:h-12 rounded-home-md bg-[#FFF7ED] flex items-center justify-center\"><img style=\"max-width: 100%; height: auto;\" title=\"frame-29-7.png\" src=\"https://laragon.net/content/uploads/2026/03/28/frame-29-7.png\" alt=\"frame-29-7.png\"></div>\r\n<h2 class=\"font-plus text-xl sm:text-2xl font-semibold text-gray-900 lg:text-2xl xl:text-3xl\">Migrate from XAMPP to Laragon</h2>\r\n</div>\r\n</div>\r\n<div class=\"px-0 sm:px-6\">\r\n<p class=\"text-sm sm:text-base text-gray-700 leading-relaxed mb-4 sm:mb-6 px-4 sm:px-0 font-plus\">Moving is easy. You just need to move your files and export/import your database.</p>\r\n<div class=\"space-y-4 sm:space-y-6 px-4 sm:px-0\"><!-- Step 1 -->\r\n<div class=\"flex gap-3 sm:gap-4\">\r\n<div class=\"flex-shrink-0 w-7 h-7 sm:w-8 sm:h-8 rounded-full bg-[#F3F4F6] flex items-center justify-center text-black text-sm sm:text-base\">1</div>\r\n<div class=\"flex-1 min-w-0\">\r\n<h3 class=\"text-sm sm:text-base font-medium text-home-heading leading-5 sm:leading-6 mb-1 sm:mb-2 font-plus\">Move Files</h3>\r\n<p class=\"text-xs sm:text-sm font-normal text-home-body leading-5 sm:leading-[22px] font-plus\">Copy folders from C:\\xampp\\htdocs to C:\\laragon\\www.</p>\r\n</div>\r\n</div>\r\n<!-- Step 2 -->\r\n<div class=\"flex gap-4\">\r\n<div class=\"flex-shrink-0 w-8 h-8 rounded-full bg-[#F3F4F6] flex items-center justify-center text-black\">2</div>\r\n<div class=\"flex-1 min-w-0\">\r\n<h3 class=\"text-sm sm:text-base font-medium text-home-heading leading-5 sm:leading-6 mb-1 sm:mb-2 font-plus\">Export Database (in XAMPP)</h3>\r\n<p class=\"text-xs sm:text-sm font-normal text-home-body leading-5 sm:leading-[22px] font-plus\">Open phpMyAdmin in XAMPP, go to Export, and save the .sql file.</p>\r\n</div>\r\n</div>\r\n<!-- Step 3 -->\r\n<div class=\"flex gap-4\">\r\n<div class=\"flex-shrink-0 w-8 h-8 rounded-full bg-[#F3F4F6] flex items-center justify-center text-black\">3</div>\r\n<div class=\"flex-1 min-w-0\">\r\n<h3 class=\"text-sm sm:text-base font-medium text-home-heading leading-5 sm:leading-6 mb-1 sm:mb-2 font-plus\">Import Database (in Laragon)</h3>\r\n<p class=\"text-xs sm:text-sm font-normal text-home-body leading-5 sm:leading-[22px] font-plus\">Start Laragon. Open HeidiSQL (Database button). Right click &gt; Load SQL file.</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '', '', '2026-03-28 13:32:18', '2026-04-01 10:58:10', '', 'usage_guide', 0, 0, 0.00),
(81, 'Troubleshooting', 'troubleshooting', '', 'active', '', NULL, '<div x-show=\"activeTab === \'troubleshooting\'\" x-transition:enter=\"transition ease-out duration-200\" x-transition:enter-start=\"opacity-0\" x-transition:enter-end=\"opacity-100\" class=\"\">\r\n                    <!-- Troubleshooting Tab Content -->\r\n<div class=\"mb-8 sm:mb-12 sm:px-0\">\r\n   \r\n\r\n    <!-- Error Sections -->\r\n    <div class=\"space-y-4 sm:space-y-6\">\r\n        <!-- Error 1: Apache fails to start -->\r\n        <div class=\"rounded-home-lg\">\r\n            <div class=\"flex items-start gap-2 sm:gap-4\">\r\n                <div class=\"flex-1 rounded-[24px] border border-gray-200 overflow-hidden mb-6 shadow-[0_2.667px_8px_0_rgba(43,140,238,0.05)]\">\r\n                        <div class=\"flex items-center gap-4 self-stretch bg-home-surface text-gray-900 p-4 sm:p-6\">\r\n                        <svg width=\"20\" height=\"20\" viewBox=\"0 0 24 24\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" class=\"flex-shrink-0\">\r\n                            <circle cx=\"12\" cy=\"12\" r=\"10\" stroke=\"#EF4444\" stroke-width=\"2\"></circle>\r\n                            <path d=\"M12 8V12M12 16H12.01\" stroke=\"#EF4444\" stroke-width=\"2\" stroke-linecap=\"round\"></path>\r\n                        </svg>\r\n                        <h3 class=\"font-plus text-[20px] sm:text-lg md:text-2xl font-semibold\"> Apache fails to start (Port 80 occupied)\r\n                        </h3>\r\n                    </div>\r\n                    <p class=\"text-sm xl:text-sm text-gray-600 p-4 sm:p-6 leading-[22px] font-normal font-plus\">\r\n                        Skype or VMWare might be using port 80. Go to Preferences &gt; Services &amp; Ports and change Apache port to 8080.\r\n                    </p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Error 2: MySQL 8.0 cannot start -->\r\n        <div class=\"rounded-home-lg\">\r\n            <div class=\"flex items-start gap-2 sm:gap-4\">\r\n                <div class=\"flex-1 rounded-[24px] border border-gray-200 overflow-hidden mb-6 shadow-[0_2.667px_8px_0_rgba(43,140,238,0.05)]\">\r\n                    <div class=\"flex items-center gap-4 self-stretch bg-home-surface text-gray-900 p-4 sm:p-6\">\r\n                        <svg width=\"20\" height=\"20\" viewBox=\"0 0 24 24\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" class=\"flex-shrink-0\">\r\n                            <circle cx=\"12\" cy=\"12\" r=\"10\" stroke=\"#EF4444\" stroke-width=\"2\"></circle>\r\n                            <path d=\"M12 8V12M12 16H12.01\" stroke=\"#EF4444\" stroke-width=\"2\" stroke-linecap=\"round\"></path>\r\n                        </svg>\r\n                        <h3 class=\"font-plus text-[20px] sm:text-lg md:text-2xl font-semibold\"> MySQL 8.0 cannot start\r\n                        </h3>\r\n                    </div>\r\n                    <p class=\"text-sm xl:text-sm text-gray-600 p-4 sm:p-6 leading-[22px] font-normal font-plus\">\r\n                        Check if you have another MySQL instance running (e.g., from XAMPP). Stop it and try again. Or check data/mysql/error.log.\r\n                    </p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Error 3: Pretty URLs not working -->\r\n        <div class=\"rounded-home-lg\">\r\n            <div class=\"flex items-start gap-2 sm:gap-4\">\r\n                <div class=\"flex-1 rounded-[24px] border border-gray-200 overflow-hidden mb-6 shadow-[0_2.667px_8px_0_rgba(43,140,238,0.05)]\">\r\n                    <div class=\"flex items-center gap-4 self-stretch bg-home-surface text-gray-900 p-4 sm:p-6\">\r\n                        <svg width=\"20\" height=\"20\" viewBox=\"0 0 24 24\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" class=\"flex-shrink-0\">\r\n                            <circle cx=\"12\" cy=\"12\" r=\"10\" stroke=\"#EF4444\" stroke-width=\"2\"></circle>\r\n                            <path d=\"M12 8V12M12 16H12.01\" stroke=\"#EF4444\" stroke-width=\"2\" stroke-linecap=\"round\"></path>\r\n                        </svg>\r\n                        <h3 class=\"font-plus text-[20px] sm:text-lg md:text-2xl font-semibold\"> Pretty URLs not working\r\n                        </h3>\r\n                    </div>\r\n                    <p class=\"text-sm xl:text-sm text-gray-600 p-4 sm:p-6 leading-[22px] font-normal font-plus\">\r\n                        Ensure you clicked \"Start All\" which reloads the hosts file. You might need to approve the UAC prompt.\r\n                    </p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n                </div>', '', '', '2026-03-28 13:33:01', '2026-04-01 10:58:56', '', 'usage_guide', 0, 0, 0.00);

