--
-- Table structure for table `fast_users`
--

CREATE TABLE `fast_users` (
  `id` int(10) UNSIGNED NOT NULL,
  `username` varchar(40) NOT NULL,
  `email` varchar(150) NOT NULL,
  `password` varchar(255) NOT NULL,
  `fullname` varchar(150) DEFAULT '',
  `birthday` date DEFAULT NULL,
  `gender` enum('male','female','other') DEFAULT 'male',
  `avatar` varchar(255) DEFAULT '',
  `coin` decimal(10,3) DEFAULT 0.000,
  `phone` varchar(30) DEFAULT NULL,
  `role` varchar(30) NOT NULL DEFAULT 'member',
  `permissions` longtext DEFAULT NULL,
  `optional` longtext DEFAULT NULL,
  `personal` longtext DEFAULT NULL,
  `country` varchar(2) NOT NULL DEFAULT '',
  `address` text DEFAULT NULL,
  `package_name` enum('membership','gold','diamond') NOT NULL DEFAULT 'membership',
  `package_exp` datetime DEFAULT NULL,
  `online` tinyint(1) NOT NULL DEFAULT 0,
  `display` tinyint(1) NOT NULL DEFAULT 0,
  `status` enum('active','inactive','banned') DEFAULT 'active',
  `password_at` datetime DEFAULT NULL,
  `activity_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `created_at` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

